// 1. הגדרת משתני מצב
const canvas = document.getElementById('paintCanvas');
const ctx = canvas.getContext('2d');
let isDrawing = false;

// הגדרות המכחול - קו עבה ולבן
ctx.lineWidth = 15;
ctx.lineCap = 'round';
ctx.strokeStyle = 'white'; 

// מבנה נתונים (מערך) לשמירת הדגימות שנייצר
let dataset = [];
let counts = { 0: 0, 1: 0, 2: 0 }; // מונה: 0=עיגול, 1=ריבוע, 2=משולש

// צביעת הלוח בשחור כברירת מחדל
ctx.fillStyle = 'black';
ctx.fillRect(0, 0, canvas.width, canvas.height);

// 2. פונקציות לאירועי העכבר (הציור בפועל)
canvas.addEventListener('mousedown', (e) => {
    isDrawing = true;
    draw(e);
});

canvas.addEventListener('mousemove', draw);

canvas.addEventListener('mouseup', stopDrawing);
canvas.addEventListener('mouseout', stopDrawing);

function draw(e) {
    if (!isDrawing) return;
    
    // מציאת קואורדינטות העכבר יחסית למיקום ה-Canvas במסך
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
}

function stopDrawing() {
    isDrawing = false;
    ctx.beginPath(); // מנתק את הקו כדי שהציור הבא לא יתחבר אליו
}

// 3. כפתור ניקוי הלוח
document.getElementById('clearCanvasBtn').addEventListener('click', () => {
    ctx.fillStyle = 'black';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
});

// 4. האלגוריתם לעיבוד התמונה (Downsampling & Normalization)
function extractImageData() {
    const targetSize = 28; // רזולוציית היעד של המודל
    const blockSize = canvas.width / targetSize; // 280 / 28 = 10
    
    // קריאת כל הפיקסלים (מערך של RGBA, כלומר 4 תאים לכל פיקסל)
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    
    // יצירת מערך חד ממדי שטוח בגודל 784, מאותחל באפסים
    let processedData = new Array(targetSize * targetSize).fill(0);

    // לולאות מקוננות: עוברים על כל בלוק של 10x10 ברשת היעד
    for (let y = 0; y < targetSize; y++) {
        for (let x = 0; x < targetSize; x++) {
            
            let pixelSum = 0;
            
            // סורקים את הפיקסלים האמיתיים בתוך הבלוק הספציפי ב-Canvas
            for (let by = 0; by < blockSize; by++) {
                for (let bx = 0; bx < blockSize; bx++) {
                    const sourceX = (x * blockSize) + bx;
                    const sourceY = (y * blockSize) + by;
                    
                    // נוסחת השטחה: מציאת האינדקס במערך החד-ממדי של התמונה המקורית
                    const index = (sourceY * canvas.width + sourceX) * 4;
                    
                    // מכיוון שציירנו בלבן על שחור, הערכים של RGB זהים. ניקח רק את ה-Red (תא ראשון)
                    pixelSum += data[index]; 
                }
            }
            
            // חישוב הממוצע של הבלוק (ערך בין 0 ל-255)
            let average = pixelSum / (blockSize * blockSize);
            
            // נרמול (Normalization) לערך עשרוני בין 0 ל-1.
            let normalized = average / 255.0;
            
            // שמירה במערך ה-784 שלנו במיקום המתאים
            processedData[y * targetSize + x] = normalized;
        }
    }
    
    return processedData;
}

// 5. לוגיקת איסוף הדגימות (בניית ה-Dataset)
document.getElementById('addSampleBtn').addEventListener('click', () => {
    const label = parseInt(document.getElementById('shapeLabel').value);
    const imageVector = extractImageData();
    
    // בדיקה שהלוח לא ריק לגמרי (מונע הכנסת דגימות "שחורות" למודל)
    const isCanvasEmpty = imageVector.every(val => val === 0);
    if (isCanvasEmpty) {
        alert('הלוח ריק! יש לצייר צורה לפני ההוספה.');
        return;
    }

    // שומרים את האובייקט: הקלט (וקטור המספרים) והתיוג (התשובה הנכונה)
    dataset.push({ input: imageVector, label: label });
    
    // עדכון ה-UI
    counts[label]++;
    document.getElementById('sampleCount').innerText = dataset.length;
    document.getElementById(`cnt${label}`).innerText = counts[label];
    
    // ניקוי אוטומטי להכנת המשטח לציור הבא
    document.getElementById('clearCanvasBtn').click();
});

// --- חיבור הלוגיקה של המודל לממשק (ui.js המשך) ---

let model = null;

// 1. נעילת פרמטרים ויצירת המודל
document.getElementById('lockModelBtn').addEventListener('click', () => {
    const hiddenNeurons = parseInt(document.getElementById('hiddenNeurons').value);
    const numFilters = parseInt(document.getElementById('filtersCount').value);
    const filterSize = parseInt(document.getElementById('filterSize').value);
    const learningRate = parseFloat(document.getElementById('learningRate').value);
    
    model = new CNNModel(numFilters, filterSize, hiddenNeurons, learningRate);
    
    // בדיקה: אם אין לבודק שמירה מקומית, אך יש לנו משקלים מוגדרים מראש בקוד
    if (!localStorage.getItem('cnnWeights') && PRETRAINED_WEIGHTS_FALLBACK) {
        localStorage.setItem('cnnWeights', PRETRAINED_WEIGHTS_FALLBACK);
    }

    // ניסיון לטעון משקלים קיימים מה-LocalStorage
    const savedWeights = localStorage.getItem('cnnWeights');
    if (savedWeights) {
        model.importWeights(JSON.parse(savedWeights));
        document.getElementById('modelStatus').innerText = "המודל נטען בהצלחה מהזיכרון המקומי!";
    } else {
        document.getElementById('modelStatus').innerText = "המודל נוצר ומוכן לאימון (אין משקלים שמורים)";
    }
    
    document.getElementById('trainBtn').disabled = false;
    document.getElementById('predictBtn').disabled = false;
});


// 2. כפתור אימון (Train)
document.getElementById('trainBtn').addEventListener('click', () => {
    if (dataset.length === 0) {
        alert("אין דגימות! הוסף ציורים לדאטה-סט לפני האימון.");
        return;
    }
    
    const epochs = parseInt(document.getElementById('epochs').value);
    document.getElementById('modelStatus').innerText = "מאמן... אנא המתן";
    
    // מנטרלים את הכפתורים בזמן האימון
    document.getElementById('trainBtn').disabled = true;
    document.getElementById('predictBtn').disabled = true;

    // משתנה מעקב אחרי מחזור האימון הנוכחי
    let currentEpoch = 1;

    // פונקציה פנימית שתבצע מחזור אימון בודד ותקרא לעצמה שוב
    function trainSingleEpoch() {
        // תנאי עצירה: הגענו למספר המחזורים המבוקש
        if (currentEpoch > epochs) {
            document.getElementById('modelStatus').innerText = "אימון הסתיים בהצלחה!";
            document.getElementById('trainBtn').disabled = false;
            document.getElementById('predictBtn').disabled = false;
            localStorage.setItem('cnnWeights', JSON.stringify(model.exportWeights()));
            return; // עוצרים את הלולאה
        }

        // --- חישובי האימון לאותו מחזור ---
        let totalLoss = 0;
        let correctPredictions = 0;
        let shuffledDataset = [...dataset].sort(() => Math.random() - 0.5);
        
        for (let i = 0; i < shuffledDataset.length; i++) {
            const sample = shuffledDataset[i];
            const result = model.trainStep(sample.input, sample.label);
            
            totalLoss += result.loss;
            if (result.correct) correctPredictions++;
        }
        
        let avgLoss = totalLoss / dataset.length;
        let accuracy = (correctPredictions / dataset.length) * 100;
        
        // --- עדכון התצוגה ---
        document.getElementById('currentEpoch').innerText = `${currentEpoch} / ${epochs}`;
        document.getElementById('currentLoss').innerText = avgLoss.toFixed(4);
        document.getElementById('currentAccuracy').innerText = `${accuracy.toFixed(2)}%`;
        
        currentEpoch++;

        setTimeout(trainSingleEpoch, 5); 
    }

    setTimeout(trainSingleEpoch, 5);
});

// 3. כפתור ניבוי (Predict)
document.getElementById('predictBtn').addEventListener('click', () => {
    if (!model) return;
    
    const imageVector = extractImageData();
    
    // אם הלוח ריק
    if (imageVector.every(val => val === 0)) {
         document.getElementById('predictionOutput').innerText = "הלוח ריק, לא ניתן לנבא.";
         return;
    }
    
    // קבלת המערך עם ההסתברויות
    const probabilities = model.predict(imageVector);
    
    // מציאת ההסתברות הגבוהה ביותר
    const maxProb = Math.max(...probabilities);
    const predictedLabel = probabilities.indexOf(maxProb);
    
    const shapeNames = ["עיגול", "ריבוע", "משולש"];
    const finalShape = shapeNames[predictedLabel];
    
    // הצגת התוצאה למשתמש
    document.getElementById('predictionOutput').innerText = `זוהה: ${finalShape} בביטחון של ${(maxProb * 100).toFixed(1)}%`;
});

// 4. כפתור איפוס (Reset)
document.getElementById('resetBtn').addEventListener('click', () => {
    if(confirm("האם אתה בטוח שברצונך לאתחל את המודל ולמחוק את המשקלים השמורים?")) {
        localStorage.removeItem('cnnWeights');
        dataset = [];
        counts = { 0: 0, 1: 0, 2: 0 };
        document.getElementById('sampleCount').innerText = 0;
        document.getElementById('cnt0').innerText = 0;
        document.getElementById('cnt1').innerText = 0;
        document.getElementById('cnt2').innerText = 0;
        document.getElementById('clearCanvasBtn').click();
        
        document.getElementById('modelStatus').innerText = "המודל אופס. נא לקבוע פרמטרים מחדש.";
        document.getElementById('trainBtn').disabled = true;
        document.getElementById('predictBtn').disabled = true;
        
        // מאלץ יצירת מודל חדש בלחיצה הבאה
        model = null; 
    }
});